-- Акклиматизация → горная болезнь
INSERT INTO kg_edges (source_node_id, target_node_id, relationship_type)
SELECT s.id, t.id, 'связано_с'
FROM kg_nodes s, kg_nodes t
WHERE s.title = '7.4. Рекомендации по высоте' AND t.title = '7.3. Горная болезнь'
  AND NOT EXISTS (SELECT 1 FROM kg_edges e WHERE e.source_node_id = s.id AND e.target_node_id = t.id);

